require"UI.UIBase"require"UI.UI_Switch"UI_PriScreen=UIBase:Inherit()UI_PriScreen.origin_x=0;UI_PriScreen.origin_y=0;UI_PriScreen.origin_scale=1;UI_PriScreen.max_scale_deviation=0.5;function UI_PriScreen:OnCreate()UI_PriScreen.Inst=self;self.canvasgroup=self.transform:GetComponent(typeof(UnityEngine.CanvasGroup))self.slider_scale=self.slider_scale:GetComponent(typeof(UnityEngine.UI.Scrollbar))self.slider_scale.onValueChanged:AddListener(function(a)self:OnZoom(a)end)self.skin=UI_Character_Skin:Init(self.illust):SetLocation(GameUtility.EIllustLocation.lobby)self.skin:SetType(GameUtility.EIllustType.lobby)self.switch=UI_Switch:Init(self.switch.transform,nil,function()self:showIllust(true)end)self.custom_skin_settings={}self.illust_base:GetComponent(typeof(UnityEngine.EventSystems.EventTrigger)).triggers[0].callback:AddListener(function()self:OnMove()end)end;function UI_PriScreen:OnShow(b)self.switch:Show(GameMgr.Inst.account_data.avatar_id)self:showIllust()self:syncScrollbar()self:SetSaveStatus(true)self.btn_showbtn.transform.gameObject:SetActive(false)self.transform.gameObject:SetActive(true)if GamePlatformInfo.GetCurrentPlatform()=='AA32'then self.btn_save.transform.gameObject:SetActive(false)self.btn_reset.transform.gameObject:SetActive(false)self.slider_scale.transform.gameObject:SetActive(false)end;self:AnimAlphaIn(self.transform,{x=0,y=0},0.2,0,function()b()end)ControllerMgr.RegistFunc(ControllerMgr.EButton.back,self.transform.gameObject,function()self:CloseLook()end)end;function UI_PriScreen:ShowBtn()self.btn_showbtn.transform.gameObject:SetActive(false)self.look_illust.transform.gameObject:SetActive(true)end;function UI_PriScreen:HideBtn()self.btn_showbtn.transform.gameObject:SetActive(true)self.look_illust.transform.gameObject:SetActive(false)end;function UI_PriScreen:OnZoom(a)local c=1+(a-0.5)/0.5*self.max_scale_deviation;self.illust_base.transform:SetLocalScale(c,c,c)self:OnMove()end;function UI_PriScreen:syncScrollbar()local c=self.illust_base.transform.localScale.x;self.slider_scale.value=(c-1)/self.max_scale_deviation*0.5+0.5 end;function UI_PriScreen:Save()if self.saved then return end;LogTool.Info('PriScreen','save custom skin settings')self:SetCustomSkinSettings(self.skin.skin_id,self.illust_base.transform.anchoredPosition.x,self.illust_base.transform.anchoredPosition.y,self.illust_base.transform.localScale.x)self:SetSaveStatus(true)end;function UI_PriScreen:Reset()self:resetToOrigin()end;function UI_PriScreen:CloseLook()if self.saved then self:CloseSelf()else UITool.ShowSecondConfirm(Tools.StrOfLocalization(3577),function()self:CloseSelf()end)end end;function UI_PriScreen:OnClose(b)self:AnimAlphaOut(self.transform,{x=0,y=0},0.2,0,function()self.transform.gameObject:SetActive(false)UIMgr.Inst:ShowUI(UI_Lobby.className)b()end)end;function UI_PriScreen:OnMove()if self.saved then self:SetSaveStatus(false)end end;function UI_PriScreen:showIllust(d)self.skin:SetSkin({skinId=GameMgr.Inst.account_data.avatar_id,partName="full",complete=function()local e=self:GetCustomSkinSettings(GameMgr.Inst.account_data.avatar_id)local c=d and 1+(self.slider_scale.value-0.5)/0.5*self.max_scale_deviation or e.scale;self.illust_base.transform:SetLocalScale(c,c,c)if not d then self.illust_base.transform:SetRectPos(e.x,e.y)end end,targetSortingOrder=self.canvasSortingOrder-1})end;function UI_PriScreen:resetToOrigin()self.illust_base.transform:SetRectPos(self.origin_x,self.origin_y)self.illust_base.transform:SetLocalScale(self.origin_scale,self.origin_scale,self.origin_scale)self.slider_scale.value=0.5;self:OnMove()end;function UI_PriScreen:SetCustomSkinSettings(f,g,h,c)if not self.custom_skin_settings[f]then self.custom_skin_settings[f]={}end;self.custom_skin_settings[f].x=g;self.custom_skin_settings[f].y=h;c=Mathf.Clamp(c,1-self.max_scale_deviation,1+self.max_scale_deviation)self.custom_skin_settings[f].scale=c;Tools.getplayerprefshandler().SetFloat(f..'x',g)Tools.getplayerprefshandler().SetFloat(f..'y',h)Tools.getplayerprefshandler().SetFloat(f..'s',c)end;function UI_PriScreen:GetCustomSkinSettings(f)self:setOriginPos(f)if not self.custom_skin_settings[f]or not self.custom_skin_settings[f].x then self.custom_skin_settings[f]={}self.custom_skin_settings[f].x=Tools.getplayerprefshandler().GetFloat(f..'x',self.origin_x)self.custom_skin_settings[f].y=Tools.getplayerprefshandler().GetFloat(f..'y',self.origin_y)self.custom_skin_settings[f].scale=Mathf.Clamp(Tools.getplayerprefshandler().GetFloat(f..'s',self.origin_scale),1-self.max_scale_deviation,1+self.max_scale_deviation)end;return self.custom_skin_settings[f]end;function UI_PriScreen:setOriginPos(f)self.origin_x,self.origin_y=0,0 end;function UI_PriScreen:ResetAllSettings()self.custom_skin_settings={}local i=ExcelMgr.GetTable('item_definition','skin')for j,k in pairs(i)do if Tools.getplayerprefshandler().GetFloat(j..'x',0)~=0 then Tools.getplayerprefshandler().SetFloat(j..'x',0)end;if Tools.getplayerprefshandler().GetFloat(j..'y',0)~=0 then Tools.getplayerprefshandler().SetFloat(j..'y',0)end;if Tools.getplayerprefshandler().GetFloat(j..'s',1)~=1 then Tools.getplayerprefshandler().SetFloat(j..'s',1)end end;UI_Lobby.Inst:RefreshInfo()end;function UI_PriScreen:SetSaveStatus(l)self.saved=l;self.btn_save_active.transform.gameObject:SetActive(not l)self.btn_save_gray.transform.gameObject:SetActive(l)self.btn_save.interactable=not l end;return UI_PriScreen